function solve(nums, k) {
    nums.sort((a, b) => a - b);
    let n = nums.length;
    if (n === 0) return 0;
    let max_len = 1;
    for (let i = 0; i < n; i++) {
        let target = nums[i] * k;
        let low = i;
        let high = n - 1;
        let j = i - 1;
        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                j = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        let current_len = j - i + 1;
        if (current_len > max_len) {
            max_len = current_len;
        }
    }
    return n - max_len;
}
